def check_backward_compatibility(old_schema, new_schema):
    """Check backward compatibility between two schemas.

    Args:
        old_schema: dict mapping field names to types
        new_schema: dict mapping field names to types

    Returns:
        dict with 'compatible' (bool) and 'breaking_changes' (list of str)
    """
    breaking_changes = []

    # Check for removed fields (in old but not in new)
    for field in old_schema:
        if field not in new_schema:
            breaking_changes.append(f"Removed field: {field}")

    # Check for type changes (field exists in both but type differs)
    for field in old_schema:
        if field in new_schema and old_schema[field] != new_schema[field]:
            breaking_changes.append(
                f"Type changed: {field} ({old_schema[field]} -> {new_schema[field]})"
            )

    return {
        "compatible": len(breaking_changes) == 0,
        "breaking_changes": breaking_changes
    }

# Fixed test schemas
old_schema = {
    "customer_id": "string",
    "email": "string",
    "name": "string",
    "created_at": "string"
}

new_schema = {
    "customer_id": "string",
    "email": "integer",
    "address": "string",
    "name": "string"
}

result = check_backward_compatibility(old_schema, new_schema)
print(result)
